import {abortMatch, commitMatch, previewMatch, randomizeMatch, showMatch, showRandom, startMatch, useControlConnection} from "../matchControl/connection";
import CurrentMatches from "../matchControl/CurrentMatches";
import ActionButtons from "../matchControl/ActionButtons";
import './HrControlTab.css'
import {Alert} from "react-bootstrap";
import {ParsedMatchTiming} from "ftc-common/utils";
import {EventTypeKind} from "ftc-common/javaTypes";
import {batchPost} from "../matchControl/api/match";

export default function HrControlTab({controlSettings, eventCode, field, showMatchTab, timing, eventType} : {controlSettings: string, eventCode: string, field: number, showMatchTab: () => void, timing: ParsedMatchTiming, eventType: string}) {
    const {
        displayUpdates,
        settings,
        isArchived,
        loadedMatch,
        activeMatch,
        matchData,
        remaining,
        loadMatch,
        nextMatchNum
    } = useControlConnection(eventCode, timing, field);
    const activeMatchRunning = activeMatch && activeMatch?.state !== 'REVIEW' && activeMatch?.state !== 'SUBMITTED';
    // only FULL can post, so only show them the warning
    const showPostWarning = loadedMatch && !activeMatchRunning && activeMatch && activeMatch.postedTime < activeMatch.start && ['FULL'].includes(controlSettings);
    const onlyRandom = 'RANDOM' === controlSettings;
    const showBetaWarning = controlSettings === 'FULL';
    if (controlSettings === "FULL" && field !== 0) {
        return <Alert variant={'warning'} className={"text-center"}>Full match control not allowed on field-bound HR page.</Alert>;
    }
    return <>
        <CurrentMatches loadedMatch={loadedMatch} activeMatch={activeMatch} matchRemaining={remaining} compact settings={settings} timing={timing} />
        <br/>
        {showPostWarning ? <Alert variant={'warning'} className={"text-center"}>If next match is started before post, the previous match will be inaccessible from this page and the control page must be used to post.</Alert> : null }
        <ActionButtons loadedMatch={loadedMatch} activeMatch={activeMatch} matches={matchData.matches}
                       previewMatch={(number) => previewMatch(eventCode, number)}
                       // if only set to random, then go back to the active match tab once randomized
                       randomizeMatch={(number, opts) => onlyRandom ? randomizeMatch(eventCode, number, opts).then(showMatchTab): randomizeMatch(eventCode, number, opts)}
                       showRandom={(number) => showRandom(eventCode, number)}
                       showMatch={(number) => showMatch(eventCode, number)}
                       startMatch={(number) => {startMatch(eventCode, number).then(showMatchTab)}}
                       abortMatch={(number, isDiscard) => abortMatch(eventCode, number, isDiscard)}
                       commitAndPostMatch={(number) => commitMatch(eventCode, number, [], true)}
                       commitMatch={(number) => commitMatch(eventCode, number, [])}
                       batchPost={(round) => batchPost(eventCode, round)}
                       hasNextMatch={nextMatchNum > 0}
                       loadNextMatch={() => loadMatch(nextMatchNum)}
                       displayUpdates={Object.values(displayUpdates)}
                       settings={settings} isArchived={isArchived} warnIfNotPost={true}
                       controlSettings={controlSettings}/>
        <br/>

        {showBetaWarning ?
        <em>
            This workflow is a beta feature. It is intended to allow small or short-staffed events to run a standardized basic
            match flow without a scorekeeper. It does not replace the need to have a computer with the control page open.
            Any post-referee score edits, out-of-order match play, Alliance Selection, and other operations must still
            be performed through the control page.
        </em> : null}
    </>
}